 55→<script webc:bucket="components">
 56→  /*
 57→    NOTE: We do an initial check/set of the scheme in layout-main.webc to avoid
 58→    an initial flash if the user has chosen dark scheme.
 59→  */
 60→
 61→  function getScheme() {
 62→    return localStorage.getItem(COLOR_SCHEME_STORAGE_KEY) || "light";
 63→  }
 64→
 65→  function applyScheme(scheme) {
 66→    document.documentElement.style.colorScheme = scheme;
 67→    document.querySelectorAll("scheme-chooser button").forEach((btn) => {
 68→      btn
 69→        .querySelector(".icon-light")
 70→        .classList.toggle("hidden", scheme !== "dark");
 71→      btn
 72→        .querySelector(".icon-dark")
 73→        .classList.toggle("hidden", scheme === "dark");
 74→    });
 75→  }
 76→
 77→  function toggleScheme(e) {
 78→    e.preventDefault();
 79→    const next = getScheme() === "light" ? "dark" : "light";
 80→    localStorage.setItem(COLOR_SCHEME_STORAGE_KEY, next);
 81→    applyScheme(next);
 82→  }
 83→
 84→  // Apply stored preference on load
 85→  applyScheme(getScheme());
 86→
 87→  document.querySelectorAll("scheme-chooser button").forEach((btn) => {
 88→    btn.addEventListener("click", toggleScheme);
 89→  });
 90→</script>
