@layer baseline, tokens, components, pages;

/* 
FIXME: There's some dumbass bug with view transitions that is causing about
a 1 second freeze of the entire screen on pages that don't have customized
transitions when coming to them from a page that does. (or something like that)
@view-transition {
  navigation: auto;
} 
*/

@layer baseline {
  html,
  div,
  span,
  object,
  iframe,
  p,
  blockquote,
  pre,
  a,
  abbr,
  acronym,
  address,
  cite,
  code,
  del,
  dfn,
  em,
  img,
  q,
  s,
  small,
  strike,
  strong,
  sub,
  sup,
  var,
  b,
  u,
  i,
  center,
  dl,
  dt,
  dd,
  ol,
  ul,
  li,
  fieldset,
  form,
  label,
  legend,
  table,
  caption,
  tbody,
  tfoot,
  thead,
  tr,
  th,
  td,
  article,
  aside,
  canvas,
  embed,
  figure,
  figcaption,
  footer,
  header,
  nav,
  section,
  time,
  mark,
  audio,
  video {
    margin: 0;
    padding: 0;
    border: 0;
    font: inherit;
    font-size: 100%;
    vertical-align: baseline;
  }

  article,
  aside,
  details,
  figcaption,
  figure,
  footer,
  header,
  hgroup,
  menu,
  nav,
  section {
    display: block;
  }

  ol,
  ul {
    list-style: none;
  }

  blockquote,
  q {
    quotes: none;
  }

  blockquote:before,
  blockquote:after,
  q:before,
  q:after {
    content: "";
    content: none;
  }

  i,
  em {
    font-style: normal;
  }

  * {
    box-sizing: border-box;
  }

  :root {
    --link-border: 1px solid color-mix(in srgb, currentColor 50%, transparent);
  }

  html,
  body {
    margin: 0;
    border: 0;
  }

  .visually-hidden {
    position: absolute !important;
    height: 1px;
    width: 1px;
    overflow: hidden;
    clip: rect(1px, 1px, 1px, 1px);
    white-space: nowrap;
  }

  .list--normal {
    list-style: inside;
    padding-bottom: 2rem;
    margin-top: 0;
  }

