 1→<script webc:type="render" webc:is="template">
 2→  module.exports = function () {
 3→    const seed = parseInt(this.seed) || 1;
 4→    let s = seed | 0;
 5→    const rand = () => {
 6→      s = (s * 1103515245 + 12345) & 0x7fffffff;
 7→      return s / 0x7fffffff;
 8→    };
 9→
10→    const randY = () => (1 + rand() * 8).toFixed(1);
11→
12→    const generatePath = () => {
13→      const pts = [`M0 ${randY()}`];
14→      for (let i = 1; i <= 4; i++) {
15→        const x = (i / 5) * 40 + (rand() - 0.5) * 6;
16→        pts.push(`L${x.toFixed(1)} ${randY()}`);
17→      }
18→      pts.push(`L40 ${randY()}`);
19→      return pts.join(" ");
20→    };
21→
22→    const d = generatePath();
23→    const values = [d, generatePath(), generatePath(), generatePath()].join(
24→      ";",
25→    );
26→    const dur = (0.4 + rand() * 0.2).toFixed(2) + "s";
27→
28→    return `<svg class="nav-stroke" viewBox="0 0 40 10" aria-hidden="true" preserveAspectRatio="none"><path d="${d}" fill="none" stroke="currentColor" stroke-width="1.4"><animate attributeName="d" calcMode="discrete" repeatCount="indefinite" dur="${dur}" values="${values}" /></path></svg>`;
29→  };
30→</script>
