    --g-max-1: calc(var(--g-col) * 1);
    --g-max-2: calc(var(--g-col) * 2 + var(--g-gutter) * 1);
    --g-max-3: calc(var(--g-col) * 3 + var(--g-gutter) * 2);
    --g-max-4: calc(var(--g-col) * 4 + var(--g-gutter) * 3);
    --g-max-5: calc(var(--g-col) * 5 + var(--g-gutter) * 4);
    --g-max-6: calc(var(--g-col) * 6 + var(--g-gutter) * 5);
